import{c as t,S as a,j as r,m as n}from"./chunks/framework.DvQr6YbT.js";const u=JSON.parse(`{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Knowlery","text":"Turn your vault into a personal knowledge review space.","tagline":"Knowlery gives Obsidian an action-first review surface for Claude Code and OpenCode workflows, with setup, diagnostics, rules, and skills maintained from settings.","image":{"src":"/knowlery-pot.svg","alt":"Knowlery Knowledge Pot logo"},"actions":[{"theme":"brand","text":"Get Started","link":"/getting-started/"},{"theme":"alt","text":"Learn the Concepts","link":"/concepts/"}]},"features":[{"title":"Action-first dashboard","details":"Start from today's move, suggested moves, the active note, recent activity, and the weekly summary without switching tabs."},{"title":"Current-note review","details":"Open a Markdown note and prepare a focused prompt for connecting it to older notes, comparisons, and reusable structures."},{"title":"Freshness Review","details":"Prepare local request JSON, import agent-written results, and approve scalar freshness metadata before anything is applied."},{"title":"Weekly summary","details":"Generate a local HTML report from recent activity, then send a polish request when a companion agent is available."},{"title":"Knowledge bundles","details":"Share reviewed knowledge as portable bundles, install bundles from others into Library/, and let /ask retrieve them deliberately."},{"title":"Settings maintenance","details":"Run diagnostics, manage rules and schema shortcuts, switch platforms, and inspect the Skills library from Obsidian settings."}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1783065655000}`),i={name:"index.md"};function s(o,e,l,d,c,p){return a(),r("div",null,[...e[0]||(e[0]=[n('<section class="knowlery-panel"><h2 id="what-knowlery-is" tabindex="-1">What Knowlery Is <a class="header-anchor" href="#what-knowlery-is" aria-label="Permalink to “What Knowlery Is”">​</a></h2><p>Knowlery is an Obsidian plugin for people who want a review-oriented layer on top of their vault.</p><p>Your free-form notes remain yours. Knowlery gives agents a structured place to work: <code>entities/</code>, <code>concepts/</code>, <code>comparisons/</code>, <code>queries/</code>, <code>KNOWLEDGE.md</code>, <code>SCHEMA.md</code>, <code>INDEX.base</code>, skills, rules, activity receipts, review requests, and platform configuration.</p></section><section class="knowlery-grid"><div class="knowlery-card"><h3>For Obsidian users</h3><p>Initialize a vault, keep structure visible, and use the dashboard to review notes, active threads, freshness suggestions, and weekly output without leaving Obsidian.</p></div><div class="knowlery-card"><h3>For agent workflows</h3><p>Give Claude Code or OpenCode durable instructions, activity receipts, and a predictable knowledge map instead of rebuilding context in every session.</p></div></section><h2 id="start-reading" tabindex="-1">Start Reading <a class="header-anchor" href="#start-reading" aria-label="Permalink to “Start Reading”">​</a></h2><ul><li>New to Knowlery? Start with <a href="/getting-started/">Getting Started</a>.</li><li>Want the mental model first? Read <a href="/concepts/">Core Concepts</a>.</li><li>Something feels broken? Go to <a href="/troubleshooting/">Troubleshooting</a>.</li><li>Need exact files and command behavior? Use the <a href="/reference/">Reference</a>.</li></ul>',4)])])}const m=t(i,[["render",s]]);export{u as __pageData,m as default};
